            className: 'gap-3',
            children: [
              Field<never>({
                orientation: 'horizontal',
                children: [
                  checkbox('finder-pref-hard-disks'),
                  FieldLabel<never>({
                    htmlFor: 'finder-pref-hard-disks',
                    className: 'font-normal',
                    children: ['Hard disks'],
                  }),
